import { useCallback, useEffect, useRef } from 'react';
import { useAtom, useAtomValue, useSetAtom } from 'jotai';
import {
    nfcScanStateAtom,
    nfcScanStartTimeAtom,
    appConfigAtom,
    workflowStateAtom,
    hardwareSimulationAtom,
    isDuplicateScanSheetOpenAtom,
    pendingDuplicateCheckAtom,
} from '../../data/atoms';
import { timeSortedChecksAtom } from '../../data/appDataAtoms';
import { useHaptics } from '../../data/useHaptics';
import { useCompleteCheck } from '../Workflow/useCompleteCheck';

/**
 * Hook for managing NFC scan state machine.
 */
export const useNfcScan = () => {
    const [scanState, setScanState] = useAtom(nfcScanStateAtom);
    const [scanStartTime, setScanStartTime] = useAtom(nfcScanStartTimeAtom);

    const appConfig = useAtomValue(appConfigAtom);
    const simulation = useAtomValue(hardwareSimulationAtom);
    const timeSortedChecks = useAtomValue(timeSortedChecksAtom);
    const workflowState = useAtomValue(workflowStateAtom);
    const setWorkflowState = useSetAtom(workflowStateAtom);
    const { trigger: triggerHaptic } = useHaptics();
    const { completeCheck } = useCompleteCheck();

    const setIsDuplicateSheetOpen = useSetAtom(isDuplicateScanSheetOpenAtom);
    const setPendingCheck = useSetAtom(pendingDuplicateCheckAtom);

    const timeoutRef = useRef<ReturnType<typeof setTimeout> | null>(null);

    // Cleanup on unmount
    useEffect(() => {
        return () => {
            if (timeoutRef.current) {
                clearTimeout(timeoutRef.current);
            }
        };
    }, []);

    // Reactive simulation sync - forces footer states when DevTools flags change
    useEffect(() => {
        if (simulation.nfcBlocked) {
            if (scanState !== 'blocked') {
                triggerHaptic('warning');
                setScanState('blocked');
                if (timeoutRef.current) clearTimeout(timeoutRef.current);
            }
        } else if (simulation.nfcTurnedOff) {
            if (scanState !== 'hardwareOff') {
                triggerHaptic('warning');
                setScanState('hardwareOff');
                if (timeoutRef.current) clearTimeout(timeoutRef.current);
            }
        } else {
            // Revert to idle if simulation flags are cleared and we were in a simulated error state
            if (scanState === 'blocked' || scanState === 'hardwareOff') {
                setScanState('idle');
            }
        }
    }, [simulation.nfcBlocked, simulation.nfcTurnedOff, scanState, setScanState, triggerHaptic]);


    const stopScan = useCallback(() => {
        if (scanState === 'idle') return;

        if (timeoutRef.current) {
            clearTimeout(timeoutRef.current);
            timeoutRef.current = null;
        }

        triggerHaptic('light');
        setScanState('idle');
        setScanStartTime(null);
    }, [scanState, setScanState, setScanStartTime, triggerHaptic]);

    // Handle valid tag read
    const handleTagRead = useCallback(() => {
        if (scanState !== 'scanning') return;

        // Check if NFC failure simulation is active
        if (simulation.nfcFails) {
            triggerHaptic('warning');
            setScanState('readError');
            return;
        }

        const targetCheck = timeSortedChecks.find(
            (c) => c.status !== 'complete' && c.type !== 'supplemental'
        );

        // Simple Scan ON = auto-complete (skip form)
        if (targetCheck && appConfig.simpleSubmitEnabled) {
            if (targetCheck.status === 'early') {
                setPendingCheck(targetCheck as any);
                setIsDuplicateSheetOpen(true);
                setScanState('idle'); // Stop NFC scanning state
                setScanStartTime(null);
                return;
            }

            const defaultStatuses = targetCheck.residents.reduce(
                (acc, resident) => {
                    acc[resident.id] = 'Awake';
                    return acc;
                },
                {} as Record<string, string>
            );

            completeCheck({
                checkId: targetCheck.id,
                statuses: defaultStatuses,
                notes: '',
                onSuccess: () => {
                    // Feedback handled by footer animation, no toast needed
                },
            });
        }

        setScanState('success');
        setScanStartTime(null);
        triggerHaptic('success');
    }, [scanState, simulation.nfcFails, setScanState, setScanStartTime, triggerHaptic, timeSortedChecks, appConfig.simpleSubmitEnabled, completeCheck, setIsDuplicateSheetOpen, setPendingCheck]);

    // Start scanning
    const startScan = useCallback(() => {
        if (scanState !== 'idle' && scanState !== 'readError' && scanState !== 'timeout' && scanState !== 'blocked' && scanState !== 'hardwareOff' && scanState !== 'success') return;

        // Step 1: Check simulation 'blocked'
        if (simulation.nfcBlocked) {
            triggerHaptic('warning');
            setScanState('blocked');
            return;
        }

        // Step 2: Check simulation 'hardware off'
        if (simulation.nfcTurnedOff) {
            triggerHaptic('warning');
            setScanState('hardwareOff');
            return;
        }

        triggerHaptic('light');
        setScanState('scanning');
        setScanStartTime(Date.now());

        // Timeout Logic
        if (appConfig.nfcTimeoutEnabled) {
            if (timeoutRef.current) clearTimeout(timeoutRef.current);
            timeoutRef.current = setTimeout(() => {
                setScanState('timeout');
                setScanStartTime(null);
                triggerHaptic('warning');
            }, appConfig.nfcScanTimeout);
        }
    }, [scanState, simulation, appConfig.nfcScanTimeout, appConfig.nfcTimeoutEnabled, setScanState, setScanStartTime, triggerHaptic]);

    // Direct restart for success loop
    const restartScan = useCallback(() => {

        // Check for simulation states first
        if (simulation.nfcBlocked) {
            triggerHaptic('warning');
            setScanState('blocked');
            return;
        }
        if (simulation.nfcTurnedOff) {
            triggerHaptic('warning');
            setScanState('hardwareOff');
            return;
        }

        // Go directly to scanning state
        triggerHaptic('light');
        setScanState('scanning');
        setScanStartTime(Date.now());

        // Restart timeout if enabled
        if (appConfig.nfcTimeoutEnabled) {
            if (timeoutRef.current) clearTimeout(timeoutRef.current);
            timeoutRef.current = setTimeout(() => {
                setScanState('timeout');
                setScanStartTime(null);
                triggerHaptic('warning');
            }, appConfig.nfcScanTimeout);
        }
    }, [simulation, appConfig.nfcTimeoutEnabled, appConfig.nfcScanTimeout, setScanState, setScanStartTime, triggerHaptic]);

    // Reset from timeout to idle
    const resetFromTimeout = useCallback(() => {
        if (scanState !== 'timeout') return;
        setScanState('idle');
    }, [scanState, setScanState]);

    // For manual simulation via UI
    const simulateTagRead = useCallback(() => {
        handleTagRead();
    }, [handleTagRead]);

    // Finalize the success state - now just handles the loop/exit
    const finalizeSuccess = useCallback(() => {
        // Handle formComplete - ALWAYS restart scan to return to Ready to Scan
        if (scanState === 'formComplete') {
            restartScan();
            return;
        }

        if (scanState !== 'success') return;

        if (appConfig.simpleSubmitEnabled) {
            // Simple Scan ON = auto-complete mode, restart scan for next check
            restartScan();
        } else {
            // Simple Scan OFF = show form for manual entry
            if (workflowState.view === 'form') {
                setScanState('idle');
                return;
            }

            const targetCheck = timeSortedChecks.find(
                (c) => c.status !== 'complete' && c.type !== 'supplemental'
            );

            setScanState('idle');
            if (targetCheck) {
                setWorkflowState({
                    view: 'form',
                    type: 'scheduled',
                    method: 'scan',
                    checkId: targetCheck.id,
                    roomName: targetCheck.residents[0].location,
                    residents: targetCheck.residents,
                    specialClassifications: targetCheck.specialClassifications,
                });
            }
        }
    }, [

        scanState,
        appConfig.simpleSubmitEnabled,
        setScanState,
        restartScan,
        timeSortedChecks,
        setWorkflowState,
        workflowState.view
    ]);

    // Calculate remaining time
    const getRemainingTime = useCallback(() => {
        if (!scanStartTime || scanState !== 'scanning') return appConfig.nfcScanTimeout;
        const elapsed = Date.now() - scanStartTime;
        return Math.max(0, appConfig.nfcScanTimeout - elapsed);
    }, [scanState, scanStartTime, appConfig.nfcScanTimeout]);

    const targetCheck = timeSortedChecks.find(
        (c) => c.status !== 'complete' && c.type !== 'supplemental'
    );
    const targetRoom = targetCheck?.residents[0]?.location || 'Room';

    return {
        scanState,
        startScan,
        stopScan,
        resetFromTimeout,
        simulateTagRead,
        finalizeSuccess,
        getRemainingTime,
        targetRoom,
        config: {
            timeout: appConfig.nfcScanTimeout,
            timeoutEnabled: appConfig.nfcTimeoutEnabled,
            showCountdown: appConfig.nfcShowCountdown,
        },
    };
};

// src/features/Workflow/ScanView.tsx
import { useState, useEffect, useCallback, useRef } from 'react';
import { useAtom, useAtomValue, useSetAtom } from 'jotai';
import { motion, AnimatePresence } from 'framer-motion';
import { Scanner } from '@yudiel/react-qr-scanner';
import {
  workflowStateAtom,
  hardwareSimulationAtom,
  isDuplicateScanSheetOpenAtom,
  pendingDuplicateCheckAtom,
} from '../../data/atoms';
import {
  safetyChecksAtom,
  timeSortedChecksAtom
} from '../../data/appDataAtoms';
import { mockResidents } from '../../data/mock/residentData';
import { addToastAtom } from '../../data/toastAtoms';
import { useHaptics } from '../../data/useHaptics';
import { useAppSound } from '../../data/useAppSound';
import { Button } from '../../components/Button';
import { appConfigAtom } from '../../data/atoms';
import { useCompleteCheck } from './useCompleteCheck';
import styles from './ScanView.module.css';

interface PreScanAlertInfo {
  residentName: string;
  classificationType: string;
}

type ScanViewState = 'scanning' | 'processing' | 'success' | 'fail';

export const ScanView = () => {
  const [workflow, setWorkflow] = useAtom(workflowStateAtom);
  const allChecks = useAtomValue(safetyChecksAtom);
  const appConfig = useAtomValue(appConfigAtom);

  const timeSortedChecks = useAtomValue(timeSortedChecksAtom);
  const simulation = useAtomValue(hardwareSimulationAtom);

  const addToast = useSetAtom(addToastAtom);

  const { trigger: triggerHaptic } = useHaptics();
  const { play: playSound } = useAppSound();
  const { completeCheck } = useCompleteCheck();

  const setIsDuplicateSheetOpen = useSetAtom(isDuplicateScanSheetOpenAtom);
  const setPendingCheck = useSetAtom(pendingDuplicateCheckAtom);

  const [scanViewState, setScanViewState] = useState<ScanViewState>('scanning');
  const [preScanAlert, setPreScanAlert] = useState<PreScanAlertInfo | null>(null);

  const lastScanned = useRef<string | null>(null);
  const lastScanTime = useRef<number>(0);

  // Show pre-scan alerts if coming from a specific check intent (e.g. manual list)
  useEffect(() => {
    if (workflow.view === 'scanning') {
      setScanViewState('scanning');
    }

    if (workflow.view === 'scanning' && workflow.targetCheckId) {
      const targetCheck = allChecks.find(c => c.id === workflow.targetCheckId);
      const firstClassification = targetCheck?.specialClassifications?.[0];
      if (firstClassification) {
        const resident = mockResidents.find(r => r.id === firstClassification.residentId);
        if (resident) {
          setPreScanAlert({
            residentName: resident.name,
            classificationType: firstClassification.type,
          });
        }
      }
    } else {
      setPreScanAlert(null);
    }
  }, [workflow, allChecks]);

  const failScan = useCallback(() => {
    // STRATEGY UPDATE: Removed redundant toast. 
    // The viewfinder's fail state overlay provides sufficient immediate feedback.
    triggerHaptic('error');
    playSound('error');
    setScanViewState('fail');
    setTimeout(() => {
      setScanViewState('scanning');
    }, 1500);
  }, [triggerHaptic, playSound]);

  const handleDecode = (result: string) => {
    if (scanViewState !== 'scanning') return;

    // Debounce duplicate scans
    if (lastScanned.current === result && (Date.now() - lastScanTime.current < 2000)) {
      return;
    }
    lastScanned.current = result;
    lastScanTime.current = Date.now();

    setScanViewState('processing');

    setTimeout(() => {
      const checkId = result.startsWith('room:') ? result.split(':')[1] : result;

      let check = allChecks.find(c => c.id === checkId && c.status !== 'complete');

      // If not found by ID (common in duplicate scans where ID changes), 
      // try to find by room name or room ID prefix
      if (!check) {
        check = allChecks.find(c =>
          c.status !== 'complete' &&
          (c.residents[0]?.location === checkId ||
            c.id.startsWith(`chk_${checkId.toLowerCase().replace(/[\s']/g, '_')}`))
        );
      }

      if (check) {
        triggerHaptic('success');
        playSound('success');
        setScanViewState('success');

        if (appConfig.simpleSubmitEnabled) {
          if (check.status === 'early') {
            setPendingCheck(check as any);
            setIsDuplicateSheetOpen(true);
            setScanViewState('scanning');
            return;
          }

          const defaultStatuses = check.residents.reduce((acc, resident) => {
            acc[resident.id] = 'Awake';
            return acc;
          }, {} as Record<string, string>);

          setWorkflow({ view: 'none' });

          completeCheck({
            checkId: check.id,
            statuses: defaultStatuses,
            notes: '',
            onSuccess: () => {
              addToast({ message: 'Check completed', icon: 'check_circle', variant: 'success' });
            }
          });
          return;
        }

        setTimeout(() => {
          setWorkflow({
            view: 'form',
            type: 'scheduled',
            method: 'scan',
            checkId: check.id,
            roomName: check.residents[0].location,
            residents: check.residents,
            specialClassifications: check.specialClassifications,
          });
        }, 800);
      } else {
        failScan();
      }
    }, 300);
  };

  const handleError = (error: unknown) => {
    if (error instanceof Error) console.log('QR Scanner Error:', error.message);
    else console.log('An unknown QR scanner error occurred:', error);
  };

  const handleClose = () => setWorkflow({ view: 'none' });



  const handleSimulateSuccess = () => {
    if (workflow.view === 'scanning' && workflow.targetCheckId) {
      handleDecode(workflow.targetCheckId);
      return;
    }
    // Always use timeSortedChecks since we only have one view now
    const actionableCandidate = timeSortedChecks.find(c =>
      c.status !== 'complete' && c.type !== 'supplemental'
    );

    if (actionableCandidate) {
      handleDecode(actionableCandidate.id);
    } else {
      const anyIncomplete = allChecks.find(c => c.status !== 'complete');
      if (anyIncomplete) {
        handleDecode(anyIncomplete.id);
      } else {
        addToast({ message: 'No incomplete checks found to simulate.', icon: 'info', variant: 'neutral' });
      }
    }
  };

  const handleSimulateFail = () => handleDecode('invalid-qr-code-id');

  const renderViewfinderContent = () => {
    if (simulation.cameraFails) {
      return (
        <div className={`${styles.statusOverlay} ${styles.failState}`}>
          <span className="material-symbols-rounded">no_photography</span>
          Camera Error
        </div>
      );
    }

    switch (scanViewState) {
      case 'scanning':
        return (
          <Scanner
            onScan={(results) => {
              if (results && results.length > 0) {
                handleDecode(results[0].rawValue);
              }
            }}
            onError={handleError}
            constraints={{ facingMode: 'environment' }}
            scanDelay={500}
          />
        );
      case 'processing':
        return (
          <div className={`${styles.statusOverlay} ${styles.processingState}`}>
            <span className={`material-symbols-rounded ${styles.spinner}`}>progress_activity</span>
            Processing...
          </div>
        );
      case 'success':
        return (
          <div className={`${styles.statusOverlay} ${styles.successState}`}>
            <span className="material-symbols-rounded">check_circle</span>
            Success!
          </div>
        );
      case 'fail':
        return (
          <div className={`${styles.statusOverlay} ${styles.failState}`}>
            <span className="material-symbols-rounded">error</span>
            Scan Failed
          </div>
        );
      default:
        return null;
    }
  };

  return (
    <motion.div
      className={styles.scanView}
      initial={{ y: '100%' }}
      animate={{ y: 0 }}
      exit={{ y: '100%' }}
      transition={{ type: 'tween', duration: 0.35, ease: [0.16, 1, 0.3, 1] }}
    >
      <header className={styles.header}>
        <h3>Scan Room QR Code</h3>
        <Button variant="on-solid" size="lg" iconOnly onClick={handleClose} aria-label="Close scanner">
          <span className="material-symbols-rounded">close</span>
        </Button>
      </header>

      <AnimatePresence>
        {preScanAlert && (
          <motion.div
            className={styles.preScanAlert}
            initial={{ y: '-100%', opacity: 0 }}
            animate={{ y: 0, opacity: 1 }}
            exit={{ y: '-100%', opacity: 0 }}
            transition={{ type: 'tween', ease: 'easeInOut', duration: 0.35 }}
          >
            <span className="material-symbols-rounded">warning</span>
            <p>
              <span>{preScanAlert.residentName}</span>
              <span className={styles.alertSeparator}>|</span>
              <span>{preScanAlert.classificationType}</span>
            </p>
          </motion.div>
        )}
      </AnimatePresence>

      <main className={styles.cameraContainer}>
        <div className={styles.viewfinder} data-scan-state={scanViewState}>
          {renderViewfinderContent()}
        </div>
        <p className={styles.helperText}>
          {simulation.cameraFails
            ? "Camera hardware is not responding."
            : "Point your camera at the room's QR code"}
        </p>
      </main>
      <footer className={styles.footer}>
        <div className={styles.devControlsContainer}>
          <p className={styles.devControlsHeader}>Dev controls</p>
          <div className={styles.devControls}>
            <Button variant="on-solid" size="s" onClick={handleSimulateSuccess} disabled={simulation.cameraFails}>
              <span className="material-symbols-rounded">check_circle</span>
              Simulate success
            </Button>
            <Button variant="on-solid" size="s" onClick={handleSimulateFail} disabled={simulation.cameraFails}>
              <span className="material-symbols-rounded">error</span>
              Simulate fail
            </Button>
          </div>
        </div>
      </footer>
    </motion.div>
  );
};
